const respuestas = items[0].json.respuestas;
const total = respuestas.length;

if (total === 0) {
  return [{ json: { texto_para_ia: 'No hay respuestas todavia.', total: 0 } }];
}

const sectores = {};
const roles = {};
const experiencias = {};
const procesos = [];

respuestas.forEach(r => {
  sectores[r.sector] = (sectores[r.sector] || 0) + 1;
  roles[r.rol] = (roles[r.rol] || 0) + 1;
  experiencias[r.experiencia_ia] = (experiencias[r.experiencia_ia] || 0) + 1;
  if (r.proceso_a_automatizar && r.proceso_a_automatizar !== 'No especificado') {
    procesos.push(`- ${r.nombre} (${r.rol}): "${r.proceso_a_automatizar}"`);
  }
});

const formatearConteos = (obj) =>
  Object.entries(obj)
    .sort((a, b) => b[1] - a[1])
    .map(([k, v]) => `  - ${k}: ${v}`)
    .join('\n');

const textoParaIA = `Analiza los resultados de esta encuesta previa a un taller de automatización con IA y n8n. Redacta un informe ejecutivo en español con este formato exacto y este orden:

**Perfil del grupo**
Describe quiénes son los asistentes en 3-4 frases. Incluye datos concretos: distribución por sectores, roles predominantes y nivel de experiencia con IA. Usa expresiones del tipo "X de cada Y" o porcentajes cuando sea posible. Señala si hay diversidad o si el grupo es homogéneo y qué implica eso para el taller.

**Procesos que quieren automatizar**
Lista los procesos mencionados, agrupados por similitud si los hay. Para cada proceso o grupo indica brevemente el potencial de automatización. Si nadie respondió, indícalo en una línea y sugiere qué preguntar durante el taller.

**Puntos clave para adaptar el taller**
- 3 recomendaciones concretas y accionables basadas en los datos del grupo
- Qué ejemplos o casos de uso resonarán más con este perfil
- Qué nivel técnico asumir en las explicaciones

Usa **negrita** para resaltar conceptos clave y datos importantes. Sé directo, preciso y evita frases genéricas como "es importante destacar" o "cabe mencionar". Máximo 320 palabras.

DATOS DE LA ENCUESTA:
Participantes: ${total}

Sectores:
${formatearConteos(sectores)}

Roles:
${formatearConteos(roles)}

Experiencia con IA:
${formatearConteos(experiencias)}

Procesos a automatizar:
${procesos.length > 0 ? procesos.join('\n') : '  (ninguno especificado)'}
`;

return [{ json: { texto_para_ia: textoParaIA, total } }];

