const texto = items[0].json.text;                                                                                                                                     

 const html = texto
   // Títulos con **texto:**
   .replace(/\*\*(.+?):\*\*/g, '<strong>$1:</strong>')
   // Negrita **texto**
   .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
   // Saltos de línea dobles → párrafos
   .replace(/\n\n/g, '</p><p>')
   // Listas con guión
   .replace(/^- (.+)$/gm, '<li>$1</li>')
   // Envolver listas en <ul>
   .replace(/(<li>.*<\/li>)/gs, '<ul>$1</ul>')
   // Saltos de línea simples
   .replace(/\n/g, '<br>');

 return [{ json: { ...items[0].json, text: '<p>' + html + '</p>' } }];

const staticData = $getWorkflowStaticData('global');
const now = new Date();
const lastRun = staticData.generadoEn ? new Date(staticData.generadoEn) : null;
if (!lastRun || (now - lastRun) >= 120000) {
  staticData.html = $input.first().json.html_informe;
  staticData.generadoEn = now.toISOString();
}
return $input.all();

const staticData = $getWorkflowStaticData('global');
const html = staticData.html || '<h2 style="font-family:sans-serif;text-align:center;padding:60px">El informe aún no ha sido generado. Vuelve en unos minutos.</h2>';
return [{ json: { html } }];
